<?php
 namespace WPAICG\Utils; use DOMDocument; use DOMXPath; if (!defined('ABSPATH')) { exit; } class AIPKit_TOC_Generator { public static function generate(string $html_content, array $options = []): array { if (empty(trim($html_content))) { return ['toc' => '', 'content' => $html_content]; } libxml_use_internal_errors(true); $dom = new DOMDocument(); $dom->loadHTML('<?xml encoding="utf-8" ?>' . $html_content, LIBXML_HTML_NOIMPLIED | LIBXML_HTML_NODEFDTD); libxml_clear_errors(); $xpath = new DOMXPath($dom); $headings = $xpath->query('//h2 | //h3 | //h4 | //h5 | //h6'); $toc_items = []; $existing_ids = []; if ($headings->length === 0) { return ['toc' => '', 'content' => $html_content]; } foreach ($headings as $heading) { $text = trim($heading->textContent); if (empty($text)) { continue; } $slug = sanitize_title($text); $original_slug = $slug; $counter = 1; while (in_array($slug, $existing_ids)) { $slug = $original_slug . '-' . $counter; $counter++; } $existing_ids[] = $slug; $heading->setAttribute('id', $slug); $toc_items[] = [ 'level' => (int) substr($heading->nodeName, 1), 'text' => $text, 'slug' => $slug, ]; } $toc_classes = ['aipkit-toc']; if (!empty($options['rank_math_compatible'])) { $toc_classes[] = 'wp-block-rank-math-toc-block'; } $toc_html = '<nav class="' . esc_attr(implode(' ', $toc_classes)) . '" aria-label="' . esc_attr__('Table of contents', 'gpt3-ai-content-generator') . '"><ul class="aipkit-toc-list">'; foreach ($toc_items as $item) { $toc_html .= sprintf( '<li class="aipkit-toc-item aipkit-toc-level-%d"><a href="#%s">%s</a></li>', esc_attr($item['level']), esc_attr($item['slug']), esc_html($item['text']) ); } $toc_html .= '</ul></nav>'; $modified_content = $dom->saveHTML(); return [ 'toc' => $toc_html, 'content' => $modified_content, ]; } } 